SELECT program_id, SUM(total_participants) AS total_participants_sum
FROM training_programs
GROUP BY program_id;

SELECT report_date
   FROM program_reports
   WHERE program_id = 1;

SELECT program_id, SUM(total_cost) AS total_resource_cost, COUNT(DISTINCT resource_name) AS resource_count
FROM program_resources
GROUP BY program_id;

SELECT year
FROM training_years
WHERE year_id = 0;

SELECT COUNT(year_id) AS total_years
FROM training_years
WHERE year_id <= 0;

SELECT total_participants
FROM training_programs
WHERE year_id = 0 AND instructor_id = 1;

SELECT AVG(rating) AS average_rating
FROM program_evaluations
WHERE program_id = 1;

SELECT total_participants
FROM training_programs
WHERE program_id = 1;

SELECT program_id, total_participants, total_hours
FROM training_programs
WHERE year_id = (SELECT year_id FROM training_years WHERE year = '2017');
